import{_ as d,c as e,o as a,a0 as r}from"./chunks/framework.C-aSrekC.js";const h=JSON.parse('{"title":"TileMap事件","description":"","frontmatter":{},"headers":[],"relativePath":"2.base/05.mapEvent.md","filePath":"2.base/05.mapEvent.md","lastUpdated":1741063516000}'),o={name:"2.base/05.mapEvent.md"};function n(i,t,l,s,p,c){return a(),e("div",null,t[0]||(t[0]=[r('<h1 id="tilemap事件" tabindex="-1">TileMap事件 <a class="header-anchor" href="#tilemap事件" aria-label="Permalink to &quot;TileMap事件&quot;">​</a></h1><p>TileMap继承于threejs的Mesh类，除了Mesh的事件外，它还有如下事件：</p><table tabindex="0"><thead><tr><th>事件名称</th><th>参数</th><th>说明</th></tr></thead><tbody><tr><td>update</td><td>delta: 时间戳</td><td>在地图每帧更新时发生，与 threejs 的渲染回调函数基本一致</td></tr><tr><td>tile-created</td><td>tile: 瓦片</td><td>在每块瓦片创建完成后发生，可在此事件中修改瓦片默认属性</td></tr><tr><td>tile-loaded</td><td>tile: 瓦片</td><td>在每块瓦片数据加载完成时发生，可在此事件中修改瓦片几何体和材质属性</td></tr><tr><td>source-changed</td><td>source: 地图数据源</td><td>在数据源对象发生变化时发生</td></tr><tr><td>projection-changed</td><td>projection: 投影对象</td><td>在地图投影发生变化时发生</td></tr><tr><td>loading-start</td><td>itemsLoaded: 加载完成数量<br>itemsTotal: 加载完成合计</td><td>在地图数据开始加载时发生（THREE.LoadingManager 事件的封装）</td></tr><tr><td>loading-error</td><td>url: 瓦片 url</td><td>在地图数据加载错误时发生（THREE.LoadingManager 事件的封装）</td></tr><tr><td>loading-complete</td><td>无</td><td>在地图数据全部加载完成时发生（THREE.LoadingManager 事件的封装）</td></tr></tbody></table>',3)]))}const m=d(o,[["render",n]]);export{h as __pageData,m as default};
